  font-size: 13.3333px;
  vertical-align: super;
}

html[saved-theme="light"] body ul.tags > li {
  --font-weight: var(--link-weight);
  background-color: var(--tag-background);
  border-bottom-color: rgba(138, 92, 245, 0.15);
  border-bottom-left-radius: 24.5px;
  border-bottom-right-radius: 24.5px;
  border-bottom-style: solid;
  border-bottom-width: 0px;
  border-left-color: rgba(138, 92, 245, 0.15);
  border-left-style: solid;
  border-left-width: 0px;
  border-right-color: rgba(138, 92, 245, 0.15);
  border-right-style: solid;
  border-right-width: 0px;
  border-top-color: rgba(138, 92, 245, 0.15);
  border-top-left-radius: 24.5px;
  border-top-right-radius: 24.5px;
  border-top-style: solid;
  border-top-width: 0px;
  color: var(--tag-color);
}

extras:
/* Slow gradient animation for accent elements */
@keyframes gradient-slow {
  from {
    background-position: right;
  }
  to {
    background-position: left;
  }
}

/* Contrast reduction for inactive notes */
@keyframes contrastFx {
  0% {
    filter: contrast(1);
  }
  100% {
    filter: contrast(0.8);
  }
}

.mod-left-split .workspace-leaf-content,
.mod-right-split .workspace-leaf-content {
  animation: contrastFx 0.3s ease forwards;
}

